        "a[int i] returns [foo f] : X ID a[3] b[34] q ;\n" +
        "b returns [int g] : Y 'y' 'if' a ;\n" +
        "a : FJKD ;\n" +
        "\n" +
        "ID : 'a'..'z'+ ID ;",
        // YIELDS
        "warning(48): A.g4:2:10: illegal option opt\n" +
        "warning(48): A.g4:2:21: illegal option k\n" +
		"error(59): A.g4:7:1: redefinition of header action\n" +
