        "a : s=ID b+=ID X=ID '.' ;\n" +
        "\n" +
        "b : x=ID x+=ID ;\n" +
        "\n" +
        "s : FOO ;",
        // YIELDS
        "error(25): B.g4:2:9: can't assign string value to token name X in non-combined grammar\n" +
		"error(35): B.g4:4:4: label s conflicts with rule with same name\n" +
